#define QK_K 256
static const int IQ2S_STRIDE = 82;    // sizeof block_iq2_s (2 + 64 + 8 + 8)
static const int Q8K_STRIDE = 292;    // sizeof block_q8_K

// ---- block formats (ggml-common.h, QK_K = 256) -------------------------------
//   block_iq2_s (82 bytes): d(fp16) @0 | qs[64] @2 | qh[8] @66 | scales[8] @74
//     qs[64] = 32 grid-index bytes (@2) then 32 explicit sign bytes (@34 = qs+QK_K/8)
//   block_q8_K (292 bytes): d(fp32) @0 | qs[256] @4 | bsums[16] @260 (unused)
typedef struct { uint16_t d; uint8_t qs[QK_K/4]; uint8_t qh[QK_K/32]; uint8_t scales[QK_K/32]; } block_iq2_s;
typedef struct { float d; int8_t qs[QK_K]; int16_t bsums[QK_K/16]; } block_q8_K;

