// WRONG grid for negative control 1: each entry's bytes incremented by 1.
static uint64_t iq2s_grid_wrong[1024];

// ---- board fp16 -> fp32 (mirrors riscv_compute_fp16_to_fp32, lossless) -------
static inline float fp16_to_fp32(uint16_t h) {
  _Float16 hf;
  std::memcpy(&hf, &h, sizeof(uint16_t));
  return (float)hf;
}

// ---- The kernel our compiler emitted (declared; defined in the linked .cpp) --
extern "C" void
tcrv_emitc_ggml_vec_dot_iq2_s_q8_K_kernel_ggml_vec_dot_iq2_s_q8_K(
    size_t n, float *s, const uint8_t *vx, const uint8_t *vy);

static void our_kernel(int n, float *s, const void *vx, const void *vy) {
  tcrv_emitc_ggml_vec_dot_iq2_s_q8_K_kernel_ggml_vec_dot_iq2_s_q8_K(
      (size_t)n, s, (const uint8_t *)vx, (const uint8_t *)vy);
}

// ---- ggml's VERBATIM _generic (quants.c:947-997) -----------------------------
// Parameterised by the grid table, a wrong-sign flag (clear bit 7 of every explicit
// sign byte), a scale-bias flag, AND a wrong-qh flag (drop the qh 2-bit injection) so
// the negative controls can break each mechanism independently. The structure is ggml's
// EXACT inner loops (the two-half ls1/ls2 split + the qh-plane index + explicit signs).
static void ggml_generic_param(int n, float *s, const void *vx, const void *vy,
                               const uint64_t *grid_tab, int wrong_signs,
                               int wrong_scale, int wrong_qh) {
  const block_iq2_s *x = (const block_iq2_s *)vx;
  const block_q8_K *y = (const block_q8_K *)vy;
  const int nb = n / QK_K;
  float sumf = 0.f;
  for (int i = 0; i < nb; ++i) {
    const float d = fp16_to_fp32(x[i].d) * y[i].d;
    const int8_t *q8 = y[i].qs;
    const uint8_t *qs = x[i].qs;
    const uint8_t *qh = x[i].qh;
    const uint8_t *signs = qs + QK_K/8;     // EXPLICIT sign region (qs+32)
    int bsum = 0;
    for (int ib32 = 0; ib32 < QK_K/32; ++ib32) {
      // wrong_scale: drop the "+1".
      int ls1 = wrong_scale ? 2*(x[i].scales[ib32] & 0xf)
                            : 1 + 2*(x[i].scales[ib32] & 0xf);
      int ls2 = wrong_scale ? 2*(x[i].scales[ib32] >> 4)
                            : 1 + 2*(x[i].scales[ib32] >> 4);
      int sumi1 = 0, sumi2 = 0;
      for (int l = 0; l < 2; ++l) {
        // wrong_qh: drop the qh 2-bit high-index injection (mask to the low 8 bits).
        int idx = wrong_qh ? qs[l]
                           : (qs[l] | ((qh[ib32] << (8 - 2*l)) & 0x300));
        const uint8_t *grid = (const uint8_t *)(grid_tab + idx);
        // wrong_signs: clear the sign bit (bit 7) of the explicit sign byte.
        uint8_t sgn = wrong_signs ? (uint8_t)(signs[l] & 0x7f) : signs[l];
        for (int j = 0; j < 8; ++j)
          sumi1 += q8[j] * grid[j] * (sgn & kmask_iq2xs[j] ? -1 : 1);
        q8 += 8;
      }
      for (int l = 2; l < 4; ++l) {
        int idx = wrong_qh ? qs[l]
                           : (qs[l] | ((qh[ib32] << (8 - 2*l)) & 0x300));
        const uint8_t *grid = (const uint8_t *)(grid_tab + idx);
        uint8_t sgn = wrong_signs ? (uint8_t)(signs[l] & 0x7f) : signs[l];
        for (int j = 0; j < 8; ++j)
          sumi2 += q8[j] * grid[j] * (sgn & kmask_iq2xs[j] ? -1 : 1);
        q8 += 8;
      }
      bsum += ls1 * sumi1 + ls2 * sumi2;
      qs += 4;
      signs += 4;
    }
    sumf += d * bsum;
  }
  *s = 0.125f * sumf;
}

static void ggml_ref(int n, float *s, const void *vx, const void *vy) {
  ggml_generic_param(n, s, vx, vy, iq2s_grid, 0, 0, 0);
}

// ---- RNG -----------------------------------------------------------------------
static uint64_t rng_state = 0x1234567890abcdefULL;
static uint32_t xrng() {
  rng_state ^= rng_state << 13;
  rng_state ^= rng_state >> 7;
  rng_state ^= rng_state << 17;
  return (uint32_t)(rng_state >> 32);
}

// Fill a random iq2_s weight block + q8_K activation block.
static void fill_random_blocks(uint8_t *xbuf, uint8_t *ybuf, int nb, int q8_mode) {
  for (int i = 0; i < nb; ++i) {
    block_iq2_s *x = (block_iq2_s *)(xbuf + i * IQ2S_STRIDE);
    block_q8_K *y = (block_q8_K *)(ybuf + i * Q8K_STRIDE);
    float dx = 0.005f + (xrng() & 0xff) * 0.0007f;
    _Float16 hx = (_Float16)dx;
    std::memcpy(&x->d, &hx, 2);
    // qs[64]: 32 random index bytes + 32 random explicit sign bytes.
    for (int k = 0; k < QK_K / 4; ++k) x->qs[k] = (uint8_t)(xrng() & 0xff);
    // qh[8]: random -- drives the high 2 index bits of each group.
    for (int k = 0; k < QK_K / 32; ++k) x->qh[k] = (uint8_t)(xrng() & 0xff);
    // scales[8]: random bytes (distinct low/high nibbles exercise ls1 != ls2).
    for (int k = 0; k < QK_K / 32; ++k) x->scales[k] = (uint8_t)(xrng() & 0xff);
    y->d = 0.01f + (xrng() & 0xff) * 0.0011f;
    for (int k = 0; k < QK_K; ++k) {
      int v;
      if (q8_mode == 1) v = 127;
      else if (q8_mode == 2) v = (k & 1) ? 127 : -127;
      else v = (int)(xrng() % 255) - 127;  // [-127,127]
      y->qs[k] = (int8_t)v;
    }
    for (int k = 0; k < QK_K / 16; ++k) y->bsums[k] = 0;
  }
}

static int g_fail = 0, g_total = 0, g_gen_delta = 0;

static int check_case(const char *name, int n, const uint8_t *xbuf,
                      const uint8_t *ybuf) {
  float s_ours = 0.f, s_ref = 0.f;
  our_kernel(n, &s_ours, xbuf, ybuf);
  ggml_ref(n, &s_ref, xbuf, ybuf);
  g_total++;
  if (std::memcmp(&s_ours, &s_ref, sizeof(float)) != 0) {
    g_fail++;
    g_gen_delta++;
    if (g_fail <= 8)
      std::printf("  FAIL %-28s n=%-6d ours=%.9g ref=%.9g (bits %08x vs %08x)\n",
                  name, n, s_ours, s_ref,
                  *(uint32_t *)&s_ours, *(uint32_t *)&s_ref);
    return 1;
  }
  return 0;
}

int main() {
  // Build the wrong-grid table (negative control).
  for (int i = 0; i < 1024; ++i) {
    uint64_t g = iq2s_grid[i];
    uint64_t w = 0;
    for (int b = 0; b < 8; ++b) {
      uint8_t by = (uint8_t)((g >> (8 * b)) & 0xff);
      w |= (uint64_t)((uint8_t)(by + 1)) << (8 * b);
    }
    iq2s_grid_wrong[i] = w;
  }

  const int MAXB = 64;
  uint8_t *xbuf = (uint8_t *)std::malloc(MAXB * IQ2S_STRIDE);
  uint8_t *ybuf = (uint8_t *)std::malloc(MAXB * Q8K_STRIDE);

  // ---- random multiples of 256 -------------------------------------------------
  int ns[] = {256, 512, 768, 1024, 2048, 4096, 8192, 16384};
  for (int rep = 0; rep < 300; ++rep) {
    for (int ni = 0; ni < 8; ++ni) {
      int n = ns[ni];
      int nb = n / QK_K;
      if (nb > MAXB) continue;
      fill_random_blocks(xbuf, ybuf, nb, 0);
      check_case("random", n, xbuf, ybuf);
    }
  }

  // ---- edge: q8 = +127 / q8 = +/-127 ------------------------------------------
  for (int rep = 0; rep < 50; ++rep) {
    fill_random_blocks(xbuf, ybuf, 8, 1);
    check_case("q8=+127", 8 * QK_K, xbuf, ybuf);
    fill_random_blocks(xbuf, ybuf, 8, 2);
    check_case("q8=+/-127", 8 * QK_K, xbuf, ybuf);
  }

  // ---- edge: marching the 10-bit grid index across the FULL [0,1023] range via
  // the qh-bit plane (the key iq2_s delta: a low-8-bit-only bug -- dropping the qh
  // injection -- passes if indices stop at 255, and a wrong shift/mask diverges on
  // the high bits). For each group, drive qs[idx-byte] = (target & 0xff) and pack
  // qh[ib32] so the 2-bit fields reproduce (target >> 8). Also hit exactly 1023, the
  // qh bit pattern, sign extremes, and scale extremes / distinct ls1!=ls2.
  int march_max_idx = 0, march_hit_1023 = 0;
  for (int extreme = 0; extreme < 3; ++extreme) {
    int nb = 8;
    fill_random_blocks(xbuf, ybuf, nb, 0);
    int idxc = 0;
    int groups = nb * (QK_K / 32) * 4;  // 8 blocks * 8 sub * 4 groups = 256 groups
    for (int i = 0; i < nb; ++i) {
      block_iq2_s *x = (block_iq2_s *)(xbuf + i * IQ2S_STRIDE);
      for (int ib = 0; ib < QK_K / 32; ++ib) {
        // pack qh[ib] so its 2-bit fields (bits injected via << (8-2*l) & 0x300)
        // reproduce the high 2 bits of each group's target index.
        uint8_t qh = 0;
        for (int l = 0; l < 4; ++l) {
          // March the 10-bit index across the FULL [0,1023] range: stride 4 covers
          // all four high-bit combos (>>8 cycles 0,1,2,3) over the 256 groups; force
          // the very LAST group to exactly 1023 so the max index is hit deterministically.
          int target = (idxc == groups - 1) ? 1023 : ((idxc * 4) & 1023);
          if (target > march_max_idx) march_max_idx = target;
          if (target == 1023) march_hit_1023 = 1;
          x->qs[ib*4 + l] = (uint8_t)(target & 0xff);   // low 8 bits
          int hi2 = (target >> 8) & 0x3;                // high 2 bits (>=256 path)
          // qh field for group l lands in bits [8,9] after << (8-2*l): qh bits
          // [2l, 2l+1] map to index bits [8,9] when qh<<(8-2*l). So qh |= hi2 << (2*l).
          qh |= (uint8_t)(hi2 << (2 * l));
          idxc++;
        }
        x->qh[ib] = qh;
        // explicit sign bytes: march the sign selector 0..255 (full bit patterns).
        for (int l = 0; l < 4; ++l)
          x->qs[QK_K/8 + ib*4 + l] = (uint8_t)((ib*4 + l) & 0xff);
        if (extreme == 0) x->scales[ib] = 0x00;          // ls1=ls2=1
        else if (extreme == 1) x->scales[ib] = 0xff;     // ls1=ls2=31
        else x->scales[ib] = (uint8_t)((ib & 0xf) | (((15 - (ib & 0xf)) & 0xf) << 4)); // ls1!=ls2
      }
    }
    const char *nm = extreme == 0 ? "grid1023-march+scale0"
                   : extreme == 1 ? "grid1023-march+scale31"
                                  : "grid1023-march+ls1!=ls2";
    check_case(nm, nb * QK_K, xbuf, ybuf);
  }

  std::printf("iq2_s byte-exact: %d/%d passed, %d failed (generic delta %d/%d)\n",
              g_total - g_fail, g_total, g_fail, g_gen_delta, g_total);
  // Prove the named march case actually drove the qh-injected high index range: the
  // 10-bit index reached the 1024-grid ceiling (the qh-plane delta is exercised, not
  // a low-8-bit-only path masquerading as covered).
  std::printf("grid-index coverage (march case): max idx = %d, hit 1023 = %s\n",
              march_max_idx, march_hit_1023 ? "YES" : "NO");
  int coverage_ok = (march_max_idx >= 1023) && march_hit_1023;

  // ---- NEGATIVE CONTROLS: grid/signs/scale/qh must be load-bearing -------------
  fill_random_blocks(xbuf, ybuf, 8, 0);
  // make scales distinct (ls1!=ls2) AND ensure qh is nonzero in every group so the
  // wrong-qh control actually bites (an all-zero qh would make wrong-qh a no-op).
  for (int i = 0; i < 8; ++i) {
    block_iq2_s *x = (block_iq2_s *)(xbuf + i * IQ2S_STRIDE);
    for (int ib = 0; ib < QK_K / 32; ++ib) {
      x->scales[ib] = (uint8_t)((ib & 0xf) | (((15 - (ib & 0xf)) & 0xf) << 4));
      x->qh[ib] = (uint8_t)0xff;  // every group's high 2 index bits set -> qh live
    }
  }
  int nbig = 8 * QK_K;
  float s_ours = 0.f;
  our_kernel(nbig, &s_ours, xbuf, ybuf);

  int controls_ok = 0;
  {
    float s_wrong = 0.f;
    ggml_generic_param(nbig, &s_wrong, xbuf, ybuf, iq2s_grid_wrong, 0, 0, 0);
    int diverges = std::memcmp(&s_ours, &s_wrong, sizeof(float)) != 0;
    std::printf("NEG-CTRL wrong-grid:  ours=%.9g wrong=%.9g -> %s\n", s_ours,
                s_wrong, diverges ? "DIVERGES (PASS)" : "MATCHES (FAIL!)");
    controls_ok += diverges;
  }
  {
    float s_wrong = 0.f;
    ggml_generic_param(nbig, &s_wrong, xbuf, ybuf, iq2s_grid, 1, 0, 0);
    int diverges = std::memcmp(&s_ours, &s_wrong, sizeof(float)) != 0;
    std::printf("NEG-CTRL wrong-signs (explicit): ours=%.9g wrong=%.9g -> %s\n", s_ours,
                s_wrong, diverges ? "DIVERGES (PASS)" : "MATCHES (FAIL!)");
    controls_ok += diverges;
  }
  {
    float s_wrong = 0.f;
    ggml_generic_param(nbig, &s_wrong, xbuf, ybuf, iq2s_grid, 0, 1, 0);
    int diverges = std::memcmp(&s_ours, &s_wrong, sizeof(float)) != 0;
    std::printf("NEG-CTRL wrong-scale: ours=%.9g wrong=%.9g -> %s\n", s_ours,
                s_wrong, diverges ? "DIVERGES (PASS)" : "MATCHES (FAIL!)");
    controls_ok += diverges;
  }
  {
    float s_wrong = 0.f;
    ggml_generic_param(nbig, &s_wrong, xbuf, ybuf, iq2s_grid, 0, 0, 1);
    int diverges = std::memcmp(&s_ours, &s_wrong, sizeof(float)) != 0;
    std::printf("NEG-CTRL wrong-qh (drop high-index plane): ours=%.9g wrong=%.9g -> %s\n",
                s_ours, s_wrong, diverges ? "DIVERGES (PASS)" : "MATCHES (FAIL!)");
    controls_ok += diverges;
  }

  std::free(xbuf);
  std::free(ybuf);

  int ok = (g_fail == 0) && (controls_ok == 4) && coverage_ok;
  std::printf("RESULT: %s\n", ok ? "ALL PASS" : "FAILURES PRESENT");
  return ok ? 0 : 1;
}
